import { useParams } from "react-router-dom";
import { GetFixtures } from "../services/fixture-service";
import { useEffect, useState } from "react";
import { Fixture } from "../objects/fixture";
import FixtureList from "../components/fixture/fixture-list";
import SeasonSummary from "../components/season/season-summary";
import { GameType } from "../objects/enums/enums";

export default function Fixtures()
{
    const param = useParams();
    const [fixtures, setFixtures] = useState<Fixture[] | null>(null);
    useEffect(() => {
        GetFixtures(param.id).then(fixture => setFixtures(fixture));
    }, []);  
    
    return(        
        <div>
            { fixtures ? 
                <>  
                    <div className="row">
                        <SeasonSummary fixtures={fixtures} gameType={GameType.League}></SeasonSummary>
                    </div> 
                    <div className="row">
                        <FixtureList fixtures={fixtures}></FixtureList> 
                    </div>
                    <div className="row">
                        <SeasonSummary fixtures={fixtures} gameType={GameType.Friendly}></SeasonSummary>
                    </div>
                </> 
                : <p>Loading...</p>}
        </div>                
    )
}
